// Initialize workflow with target parameters
const inputData = $input.all();

// Check if data comes from webhook or use defaults
const webhookData = inputData.find(item => item.json.body);
const hasWebhookInput = webhookData && Object.keys(webhookData.json.body).length > 0;

const config = {
  keywords: hasWebhookInput ? 
    (webhookData.json.body.keywords || ['Fintech founders', 'SaaS startups']) :
    ['Fintech founders', 'SaaS startups'],
  industries: hasWebhookInput ?
    (webhookData.json.body.industries || ['Technology', 'Software']) :
    ['Technology', 'Software'],
  location: hasWebhookInput ?
    (webhookData.json.body.location || 'United States') :
    'United States',
  companySize: hasWebhookInput ?
    (webhookData.json.body.companySize || '11-50') :
    '11-50',
  maxResults: hasWebhookInput ?
    (webhookData.json.body.maxResults || 50) :
    50,
  executionId: $execution.id,
  timestamp: new Date().toISOString()
};

return {
  json: config
};

// Merge and normalize data from multiple sources
const items = $input.all();
const normalizedLeads = [];
const errors = [];

for (const item of items) {
  try {
    // Handle Apollo.io response
    if (item.json.people) {
      for (const person of item.json.people) {
        normalizedLeads.push({
          source: 'apollo',
          firstName: person.first_name,
          lastName: person.last_name,
          fullName: `${person.first_name} ${person.last_name}`,
          email: person.email,
          title: person.title,
          company: person.organization?.name,
          companyDomain: person.organization?.primary_domain,
          companyIndustry: person.organization?.industry,
          companySize: person.organization?.estimated_num_employees,
          linkedinUrl: person.linkedin_url,
          location: person.city ? `${person.city}, ${person.state}` : person.state,
          country: person.country,
          rawData: JSON.stringify(person),
          scrapedAt: new Date().toISOString(),
          executionId: $execution.id
        });
      }
    }

    // Handle Phantombuster response
    if (item.json.container) {
      const resultUrl = item.json.container.resultObject?.csvUrl;
      if (resultUrl) {
        // Note: You'd fetch and parse the CSV in a follow-up HTTP Request node
        normalizedLeads.push({
          source: 'phantombuster',
          phantombusterResultUrl: resultUrl,
          containerId: item.json.container.id,
          status: 'pending_csv_fetch',
          executionId: $execution.id
        });
      }
    }

    // Handle direct CSV/structured data
    if (Array.isArray(item.json) || item.json.results) {
      const data = Array.isArray(item.json) ? item.json : item.json.results;
      for (const record of data) {
        normalizedLeads.push({
          source: 'custom',
          firstName: record.firstName || record.first_name,
          lastName: record.lastName || record.last_name,
          fullName: record.fullName || `${record.firstName} ${record.lastName}`,
          email: record.email,
          title: record.title || record.jobTitle,
          company: record.company || record.companyName,
          companyDomain: record.website || record.domain,
          linkedinUrl: record.linkedIn || record.linkedin_url,
          rawData: JSON.stringify(record),
          scrapedAt: new Date().toISOString(),
          executionId: $execution.id
        });
      }
    }
  } catch (error) {
    errors.push({
      error: error.message,
      itemIndex: items.indexOf(item),
      rawItem: JSON.stringify(item),
      timestamp: new Date().toISOString()
    });
  }
}

return normalizedLeads.map(lead => ({ json: lead }));

// Deduplicate leads and validate data quality
const items = $input.all();
const seen = new Map();
const validLeads = [];
const invalidLeads = [];

// Email validation regex
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

for (const item of items) {
  const lead = item.json;

  // Create unique key (email + company or linkedinUrl)
  const uniqueKey = lead.email ? 
    `${lead.email.toLowerCase()}_${lead.company}` : 
    lead.linkedinUrl;

  // Skip if duplicate
  if (seen.has(uniqueKey)) {
    continue;
  }

  // Validate required fields
  const isValid = (
    lead.fullName && lead.fullName.length > 2 &&
    (lead.email ? emailRegex.test(lead.email) : lead.linkedinUrl) &&
    lead.company && lead.company.length > 1
  );

  if (isValid) {
    seen.set(uniqueKey, true);

    // Add data quality score
    let qualityScore = 0;
    if (lead.email && emailRegex.test(lead.email)) qualityScore += 30;
    if (lead.linkedinUrl) qualityScore += 20;
    if (lead.title) qualityScore += 15;
    if (lead.companyDomain) qualityScore += 15;
    if (lead.companyIndustry) qualityScore += 10;
    if (lead.location) qualityScore += 10;

    validLeads.push({
      ...lead,
      uniqueKey,
      dataQualityScore: qualityScore,
      validatedAt: new Date().toISOString()
    });
  } else {
    invalidLeads.push({
      ...lead,
      validationError: 'Missing required fields or invalid email',
      timestamp: new Date().toISOString()
    });
  }
}

// Store both valid and invalid for logging
return [
  ...validLeads.map(lead => ({ json: lead })),
  ...invalidLeads.map(lead => ({ json: { ...lead, isInvalid: true } }))
];

