// Handle email sending errors
const items = $input.all();
const errorLogs = [];

for (const item of items) {
  if (item.json.error) {
    errorLogs.push({
      lead_id: item.json.lead_id,
      error_message: item.json.error.message || 'Unknown error',
      failed_at: new Date().toISOString()
    });
  }
}

return errorLogs.map(log => ({ json: log }));

// Prepare data for embedding
const items = $input.all();
const output = [];

for (const item of items) {
  const embeddingText = `
Company: ${item.json.company_name}
Industry: ${item.json.company_industry || 'Unknown'}
Size: ${item.json.company_size || 'Unknown'}
Description: ${item.json.company_description}
  `.trim();

  output.push({
    json: {
      ...item.json,
      embedding_text: embeddingText,
      lead_id: item.json.id
    }
  });
}

return output;

