const items = $input.all();
const output = [];

for (const item of items) {
  try {
    const aiResponse = JSON.parse(item.json.choices[0].message.content);
    const leadContext = item.json.lead_context;

    output.push({
      json: {
        lead_id: leadContext.lead_id,
        company_name: leadContext.company_name,
        contact_email: leadContext.contact_email,
        contact_name: leadContext.contact_name,
        score: aiResponse.score,
        reasoning: aiResponse.reasoning,
        key_strengths: aiResponse.key_strengths,
        potential_concerns: aiResponse.potential_concerns,
        recommended_action: aiResponse.recommended_action,
        scored_at: new Date().toISOString()
      }
    });
  } catch (error) {
    // Log parsing error
    const leadContext = item.json.lead_context || {};
    output.push({
      json: {
        lead_id: leadContext.lead_id,
        company_name: leadContext.company_name,
        error: 'Failed to parse AI response',
        raw_response: item.json.choices?.[0]?.message?.content || 'No response',
        score: 0
      }
    });
  }
}

return output;

