// Parse email generation and combine with scoring
const items = $input.all();
const output = [];

for (const item of items) {
  const scoringData = $('Parse Scoring Results1').item.json;

  try {
    const emailContent = JSON.parse(item.json.choices[0].message.content);

    output.push({
      json: {
        lead_id: scoringData.lead_id,
        company_name: scoringData.company_name,
        contact_email: scoringData.contact_email,
        contact_name: scoringData.contact_name,
        score: scoringData.score,
        reasoning: scoringData.reasoning,
        key_strengths: JSON.stringify(scoringData.key_strengths),
        potential_concerns: JSON.stringify(scoringData.potential_concerns),
        recommended_action: scoringData.recommended_action,
        email_subject: emailContent.subject,
        email_body: emailContent.body,
        scored_at: scoringData.scored_at,
        email_generated: true
      }
    });
  } catch (error) {
    output.push({
      json: {
        lead_id: scoringData.lead_id,
        company_name: scoringData.company_name,
        contact_email: scoringData.contact_email,
        contact_name: scoringData.contact_name,
        score: scoringData.score,
        reasoning: scoringData.reasoning,
        key_strengths: JSON.stringify(scoringData.key_strengths),
        potential_concerns: JSON.stringify(scoringData.potential_concerns),
        recommended_action: scoringData.recommended_action,
        scored_at: scoringData.scored_at,
        email_generated: false,
        email_error: 'Failed to generate email: ' + error.message
      }
    });
  }
}

return output;

