const output = [];

for (const item of items) {
  output.push({
    json: {
      lead_id: item.json.lead_id,
      company_name: item.json.company_name,
      contact_email: item.json.contact_email,
      contact_name: item.json.contact_name,
      score: item.json.score,
      reasoning: item.json.reasoning,
      key_strengths: JSON.stringify(item.json.key_strengths),
      potential_concerns: JSON.stringify(item.json.potential_concerns),
      recommended_action: item.json.recommended_action,
      scored_at: item.json.scored_at,
      email_subject: null,
      email_body: null
    }
  });
}

return output;

// Generate summary statistics
const allItems = $input.all();

if (allItems.length === 0) {
  return [{
    json: {
      total_processed: 0,
      high_score_count: 0,
      medium_score_count: 0,
      low_score_count: 0,
      average_score: 0,
      emails_generated: 0,
      processed_at: new Date().toISOString(),
      status: 'no_leads_processed'
    }
  }];
}

const stats = {
  total_processed: allItems.length,
  high_score_count: allItems.filter(i => i.json.score >= 60).length,
  medium_score_count: allItems.filter(i => i.json.score >= 40 && i.json.score < 60).length,
  low_score_count: allItems.filter(i => i.json.score < 40).length,
  average_score: Math.round(allItems.reduce((sum, i) => sum + (i.json.score || 0), 0) / allItems.length),
  emails_generated: allItems.filter(i => i.json.email_subject).length,
  processed_at: new Date().toISOString(),
  status: 'success'
};

return [{ json: stats }];
